mapper.select:
SELECT id, user_id, session_id, role, content, create_time
FROM ai_chat_record
WHERE session_id = #{sessionId}
ORDER BY create_time ASC
LIMIT #{limit}

mapper.update:
UPDATE ai_chat_session
SET status = '归档', update_time = now()
WHERE session_id = #{sessionId}
  AND user_id = #{userId}
